#include <stdio.h>
#include <stdlib.h>
#include <limits.h>
#include <ctype.h>
#include <errno.h>
#include <stdbool.h>

/* Safely validates if a string contains a valid, in-range integer */
bool parse_integer(const char *str, long *out_val) {
    if (str == NULL || *str == '\0') {
        return false;
    }

    /* Skip leading whitespace using ctype.h */
    while (isspace((unsigned char)*str)) {
        str++;
    }

    char *endptr;
    errno = 0; /* Reset global error indicator */
    long val = strtol(str, &endptr, 10);

    /* Check for overflow or underflow limits */
    if ((val == LONG_MAX || val == LONG_MIN) && errno == ERANGE) {
        return false;
    }

    /* Check if no conversion occurred */
    if (str == endptr) {
        return false;
    }

    /* Check for trailing garbage (excluding whitespace) */
    while (*endptr != '\0') {
        if (!isspace((unsigned char)*endptr)) {
            return false;
        }
        endptr++;
    }

    *out_val = val;
    return true;
}

int main(void) {
    const char *test_input = "  42735abc";
    const char *valid_input = " -1984 ";
    long result = 0;

    if (parse_integer(valid_input, &result)) {
        printf("Successfully parsed integer: %ld\n", result);
    } else {
        printf("Failed to parse: '%s'\n", valid_input);
    }

    if (parse_integer(test_input, &result)) {
        printf("Successfully parsed: %ld\n", result);
    } else {
        printf("Invalid entry rejected: '%s'\n", test_input);
    }

    return 0;
}

