#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>
#include <stdint.h>

#define BUFFER_SIZE 64
#define ITERATIONS 1000000

typedef struct {
    uint64_t id;
    char log_message[BUFFER_SIZE];
} LogEntry;

int main(void) {
    clock_t start_time = clock();

    /* Dynamically allocate memory for standard struct alignment */
    LogEntry *entry = malloc(sizeof(LogEntry));
    if (entry == NULL) {
        perror("Failed to allocate memory");
        return EXIT_FAILURE;
    }

    entry->id = 998877;

    /* Safely clear structure payload using memset */
    memset(entry->log_message, 0, BUFFER_SIZE);

    /* Assemble structured buffer securely using snprintf */
    int written = snprintf(entry->log_message, BUFFER_SIZE, "SysStatus: ACTIVE, Code: %04X", 1023);
    if (written < 0 || written >= BUFFER_SIZE) {
        fprintf(stderr, "Buffer output was truncated!\n");
    }

    /* Perform dummy high-frequency operations */
    uint64_t hash = 0;
    for (uint32_t i = 0; i < ITERATIONS; i++) {
        hash += entry->id ^ (uint64_t)entry->log_message[i % 8];
    }

    clock_t end_time = clock();
    double cpu_seconds = (double)(end_time - start_time) / CLOCKS_PER_SEC;

    printf("Log Message: %s\n", entry->log_message);
    printf("Execution metrics: %.6f seconds total, hash value: %lx\n", cpu_seconds, (unsigned long)hash);

    free(entry);
    return EXIT_SUCCESS;
}

