#include <stdio.h>
#include <time.h>

void print_future_date(void) {
    time_t now = time(NULL);
    if (now == (time_t)-1) return;

    struct tm *future = localtime(&now);
    if (!future) return;

    future->tm_mday += 10; /* Temporarily overflow days field */

    /* mktime automatically normalizes tm_mday and updates other fields */
    if (mktime(future) == (time_t)-1) {
        printf("Normalization error\n");
        return;
    }

    char buffer[64];
    strftime(buffer, sizeof(buffer), "%Y-%m-%d %H:%M:%S", future);
    printf("Date 10 days from now: %s\n", buffer);
}

#include <stdint.h>
#include <stddef.h>
#include <stdbool.h>

bool safe_memcpy(void *dest, size_t dest_size, const void *src, size_t count) {
    if (dest == NULL || src == NULL || count == 0) {
        return false;
    }
    if (count > dest_size) {
        return false; /* Prevent buffer overflow */
    }

    uintptr_t d_addr = (uintptr_t)dest;
    uintptr_t s_addr = (uintptr_t)src;

    /* Check for overlapping memory regions */
    if ((d_addr >= s_addr && d_addr < s_addr + count) || 
        (s_addr >= d_addr && s_addr < d_addr + count)) {
        return false; /* Overlap detected: unsafe for memcpy */
    }

    uint8_t *d = (uint8_t *)dest;
    const uint8_t *s = (const uint8_t *)src;
    for (size_t i = 0; i < count; i++) {
        d[i] = s[i];
    }
    return true;
}

questionsAndAnswers.question:
Explain the safety issue with the code below, and rewrite it using safe string operations:
char buffer[16];
strcpy(buffer, user_input);

questionsAndAnswers.answer:
The safety issue is that strcpy does not perform bounds checking. If user_input is longer than 15 characters, it will overflow buffer, corrupting the stack frame and potentially allowing arbitrary code execution.

Here is the safe rewrite:
#include <stdio.h>
#include <string.h>

void safe_copy(const char *user_input) {
    char buffer[16];
    /* snprintf guarantees null-termination and prevents overflows */
    int written = snprintf(buffer, sizeof(buffer), "%s", user_input);
    if (written >= (int)sizeof(buffer)) {
        fprintf(stderr, "Input truncated!\n");
    }
}

questionsAndAnswers.question:
Identify the integer overflow/promotion bugs in this code, and explain how to fix them:
uint16_t x = 60000;
uint16_t y = 20000;
uint32_t result = x * y;

questionsAndAnswers.answer:
The bugs are: 
1. Integer promotion: In C, integer types smaller than 'int' (like uint16_t) are promoted to signed 'int' before arithmetic operations are performed. 
2. Signed Overflow: On platforms with a 32-bit int, the multiplication '60000 * 20000' equals 1,200,000,000, which fits in a signed 32-bit int. However, if 'int' is 16-bit, this causes signed overflow (undefined behavior).
3. If the compiler evaluates this using standard promotions, the multiplication is performed as signed integers. If we use larger values, the intermediate calculation can overflow before being assigned to the 32-bit result.

To fix this, cast one of the operands to the target width (uint32_t) to force the multiplication to be evaluated in 32-bit space:

uint16_t x = 60000;
uint16_t y = 20000;
uint32_t result = (uint32_t)x * y;

#include <string.h>
#include <ctype.h>

void trim_string(char *str) {
    if (str == NULL) return;

    /* Handle leading whitespaces */
    char *start = str;
    while (*start && isspace((unsigned char)*start)) {
        start++;
    }

    /* Shift string contents left if needed */
    if (start != str) {
        memmove(str, start, strlen(start) + 1);
    }

    /* Handle trailing whitespaces */
    size_t len = strlen(str);
    while (len > 0 && isspace((unsigned char)str[len - 1])) {
        str[len - 1] = '\0';
        len--;
    }
}

#define _POSIX_C_SOURCE 199309L
#include <stdio.h>
#include <time.h>
#include <stdint.h>

int64_t get_elapsed_nanoseconds(struct timespec start, struct timespec end) {
    int64_t sec_diff = (int64_t)end.tv_sec - (int64_t)start.tv_sec;
    int64_t nsec_diff = (int64_t)end.tv_nsec - (int64_t)start.tv_nsec;

    return (sec_diff * 1000000000LL) + nsec_diff;
}

int main(void) {
    struct timespec start, end;

    if (clock_gettime(CLOCK_MONOTONIC, &start) != 0) {
        return 1;
    }

    /* Simulated workload */
    volatile uint64_t sum = 0;
    for (uint32_t i = 0; i < 5000000; i++) {
        sum += i;
    }

    if (clock_gettime(CLOCK_MONOTONIC, &end) != 0) {
        return 1;
    }

    int64_t total_ns = get_elapsed_nanoseconds(start, end);
    printf("Elapsed processing duration: %lld ns\n", (long long)total_ns);
    return 0;
}

